mapper.select:
SELECT am.id, am.name, am.description, am.question_bank_id AS questionBankId, tqb.name AS questionBankName, am.status, am.creator, creator_user.nickname AS creatorName, am.add_datetime AS addDatetime, am.operator, operator_user.nickname AS operatorName, am.operation_datetime AS operationDatetime, COUNT(amm.id) AS teachingMaterialsCount FROM application_materials am LEFT JOIN teaching_question_bank tqb ON am.question_bank_id = tqb.id LEFT JOIN sys_tbuser creator_user ON am.creator = creator_user.id LEFT JOIN sys_tbuser operator_user ON am.operator = operator_user.id LEFT JOIN application_materials_mapping amm ON am.id = amm.application_material_id
AND am.name LIKE CONCAT('%', #{param.name}, '%')
AND am.question_bank_id = #{param.questionBankId}
AND am.status = #{param.status}
AND am.creator = #{param.creator}
GROUP BY am.id, am.name, am.description, am.question_bank_id, tqb.name, am.status, am.creator, creator_user.nickname, am.add_datetime, am.operator, operator_user.nickname, am.operation_datetime ORDER BY am.add_datetime
ASC DESC
